<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div class="my-popups">
            <div class="modal fade dialog my-popups ui-draggable show"
                style="height: auto; width: auto; display: block; top: 0px; left: 0px;" data-keyboard="false"
                data-backdrop="static" role="dialog">
                <div role="document" class="modal-dialog maxwidth500">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 id="myModalLabel" class="modal-title text-truncate pb-1">{{ $t('UploadFile') }} </h5>

                            <button type="button" data-dismiss="modal" class="close" v-on:click="closePopup"><i
                                    aria-hidden="true" class="fa fa-times"></i></button>
                        </div>
                        <div class="modal-body maxht-scroll">
                            <span class="user-guide">
                                <a class="ancuserguide" data-toggle="collapse" href="#collapseReply" role="button"
                                    aria-expanded="false" aria-controls="collapseExample">{{ $t('UserGuide') }}</a>
                                <div id="collapseReply" class="divancuserguide collapse">
                                    <div id="scrollbarreplyuserguide" class="custom-scrollbar-js"
                                        style="overflow: auto;">
                                        <div class="con" v-html="$t('User_Guide_Quick_View_Add_File')"></div>
                                    </div>
                                </div>
                            </span>
                            <dynamic-form lang="en" ref="modalAddFile" :schema="FormSchema">
                            </dynamic-form>
                            <div class="row">
                                <div class="col-lg-12 mb-3">
                                    <div class="heading-border mt-2">
                                        <h5 class="h5"><span>{{ $t('Visibleto') }}</span></h5>
                                    </div>
                                </div>
                            </div>
                            <div class="col-md-12 col-lg-12 col-xl-12 float-left p-0 mb-2 lastchild-control"
                                v-for="item in UserData" :key="item.userTypeId" v-if="UserData.length > 0"
                                style="max-height: 450px; overflow-y: auto; border-bottom: 1px solid #dee2e6 !important; border-top: 1px solid #dee2e6 !important;">
                                <div class="form-group row m-0 border p-2 bg-f5f5f5">
                                    <div class="custom-control custom-checkbox">
                                        <input name="usertypes" type="checkbox" :value="item.userTypeId"
                                            :id="'userType-' + item.userTypeId" class="custom-control-input"
                                            v-model="item.ParentSelected" @change="CheckAllUsers($event, item)">
                                        <label class="custom-control-label universal-custom-control-label pt-1"
                                            :for="'userType-' + item.userTypeId"></label>
                                        <span class="clsprivdata ml-1">{{ item.userType }}</span>
                                    </div>
                                </div>
                                <ul class="row m-0 p-0 py-3 mb-3 border border-top-0">
                                    <li class="col-sm-12 col-md-4 col-lg-3 col-xl-3 float-left pl-2 mb-2"
                                        style="list-style: none;" v-for="obj in item.userses" :key="obj.id">
                                        <div class="custom-control custom-checkbox">
                                            <input name="users" type="checkbox" :value="obj.id"
                                                v-model="obj.ChildSelected" :id="'user-' + obj.id"
                                                class="custom-control-input" @click="ToggleCheck(obj, item)">
                                            <label class="custom-control-label universal-custom-control-label pt-1"
                                                :for="'user-' + obj.id"></label>
                                            {{ obj.name }}
                                        </div>
                                    </li>
                                </ul>
                            </div>
                            <div class="col-md-12 col-lg-12 p-0" v-if="UserData.length == 0">
                                <div
                                    class="text-center text-danger d-flex align-items-center justify-content-center borderbababa px-2 py-2 no-record">
                                    {{ $t('NoRecordfound') }}
                                </div>
                            </div>
                        </div>
                        <div class="col-lg-12 text-right mt-4 mb-3">
                            <a href="javascript:UploadFile(0);" title="Save" class="btn btn-success text-white mr-2"
                                @click="onSubmit()"><i class="fa fa-upload pr-2"></i>{{ $t('Upload')
                                }}</a>
                            <a title="Cancel" class="btn btn-danger text-white" @click="closePopup()"><i
                                    class="fa fa-close pr-2"></i>{{ $t("Cancel") }}</a>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataService from '../../services/DataService';
export default {
    props: {
        ProjectDetails: {
            type: Number
        },
        taskId: {
            type: Number
        }
    },
    data() {
        return {
            isLoading: false,
            GetUserList: [],
            checkBoxUser: [],
            FileId:0,
            checkBoxUserType: false,
            selectedUserTypeId: 0,
            fileName: '',
            attachement_mime: '',
            base64String: '',
            fileData: [],
            modelUserId: '',
            modelInnerUserId: '',
            FormSchema: [
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('FileTitle'),
                            name: "FileTitle",
                            value: "",
                            placeholder: "Enter File Title",
                            config: {
                                options: [],
                            },
                            validationRules: {
                                "required": true,
                            },
                        },
                        {
                            astype: "FileField",
                            label: this.$t('File'),
                            showLabel: true,
                            name: "Attachment",
                            placeholder: "",
                            validationRules: "required",
                            FieldIndex: 0,
                            config: {
                                maxSize: 100,
                                accept: [
                                    {
                                            fileType: 'jpg', 
                                            iconClass: 'fa-file-image-o' 
                                        },
                                        {
                                            fileType: 'jpeg', 
                                            iconClass: 'fa-file-image-o' 
                                        },
                                        {
                                            fileType: 'png', 
                                            iconClass: 'fa-file-image-o' 
                                        },
                                        {
                                            fileType: 'pdf',
                                            iconClass: 'fa-file-archive-o'
                                        },
                                        {
                                            fileType: 'mp4',
                                            iconClass: 'fa-video-camera'
                                        },
                                        {
                                            fileType: 'doc',
                                            iconClass: 'fa-file-text-o'
                                        },
                                        {
                                            fileType: 'docx',
                                            iconClass: 'fa-file-text-o'
                                        },
                                        {
                                            fileType: 'xlsx',
                                            iconClass: 'fa-file-excel-o'
                                        },
                                        {
                                            fileType: 'txt', 
                                            iconClass: 'fa-file-text-o' 
                                        },
                                        {
                                            fileType: 'xls', 
                                            iconClass: 'fa-file-excel-o' 
                                        }
                                ],
                                onChange: this.previewFiles,
                                showAddIcon: false,
                                onAddButtonClick: "",
                                multiple: false
                            },
                        }
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",
                            mode: "tag",
                            placeholder: "",
                            config: {
                                options: [],
                            },
                            validationRules: {
                                "required": true
                            },
                        }
                    ]
                }

            ],
            UserData: [],
            buttons: [
               
            ],
            model: {
                FileId: 0,
                FileName: '',
                FilePath: '',
                FileTitle: '',
                FileContent: '',
                UserList: [],
                FileVersion: 0,
                ProjectId: 0,
                TaskId: 0,
                FileDetail: '',
                StatusId: 0,
                FileCategoryId: 0,
                RequestType: 'first',
                formData: {},
                PMTeam: [],
                ClientData: []

            },
            Userids:'',
            SelectedIds:[],
            getFileName:''

        }
    },
    created() {
        debugger;
        var vm = this;
        vm.FetchUserListing();
    },
    methods: {
        FetchUserListing: function () {
            var ths = this;
            var url = `projectId=${ths.ProjectDetails}`;
            debugger
            DataService.UserList(url).then((response) => {
                const result = response.data.result || [];
                const grouped = {};
                result.forEach(user => {
                    if (!grouped[user.user_type_id]) {
                        grouped[user.user_type_id] = {
                            userTypeId: user.user_type_id,
                            userType: user.user_type_desc,
                            ParentSelected: false,
                            userses: []
                        };
                    }
                    grouped[user.user_type_id].userses.push({
                        id: user.user_id,
                        name: user.name,
                        ChildSelected: false
                    });
                });

                this.UserData = Object.values(grouped);
            });
        },
        CheckAllUsers(event, item) {
            var vm = this;
            this.UserData.forEach(element => {
                if (event.target.checked == true) {
                    if (element.userTypeId == item.userTypeId) {
                        element.userses.forEach(ele => {
                            ele.ChildSelected = true;
                            if (ele.ChildSelected) {
                                vm.SelectedIds.push(ele.id);
                            }
                        })
                    }

                } else {
                    if (element.userTypeId == item.userTypeId) {
                        element.userses.forEach(ele => {
                            ele.ChildSelected = false;
                        })
                    }
                }
            })
            vm.Userids = vm.SelectedIds.join(",");
        },
        ToggleCheck(Cobject, Pobject) {
            debugger
            var vm = this;
            const user = Pobject.userses.find(user => user.id === Cobject.id);
            if (user) {
                user.ChildSelected = !user.ChildSelected;
            }
            if (Cobject.ChildSelected) {
                vm.SelectedIds.push(Cobject.id);
            } else {
                const index = vm.SelectedIds.indexOf(Cobject.id);
                if (index > -1) {
                    vm.SelectedIds.splice(index, 1);
                }
            }
            const totalUsersesLength = Pobject.userses.length;
            const checkedChildSelectedCount = Pobject.userses.filter(user => user.ChildSelected === true).length;
            if (totalUsersesLength == checkedChildSelectedCount) {
                Pobject.ParentSelected = true;
            }
            else {
                Pobject.ParentSelected = false;
            }
            vm.Userids = vm.SelectedIds.join(",");

        },
        closePopup() {
            this.$parent.ShowManageFile = false;
        },
        previewFiles(event) {
            var vm = this;
            vm.fileData.push(event.target.files[0]);
            vm.getFileName = event.target.files[0].name;
        },
        async onSubmit() {
            var vm = this;
            vm.isLoading = true;            
            if (vm.fileData == "") {
                vm.ShowAlert(vm.$t('SelectFileUpload'), "warning", true, vm.$t('Alert'));
                vm.isLoading = false;
                return false;
            }

            if (vm.Userids == "") {
                vm.ShowAlert(vm.$t('SelectUserToShareFile'), "warning", true, vm.$t('Alert'));
                vm.isLoading = false;
                return false;
            }
            else {
                 let formData = new FormData();
                    formData.append("file", vm.fileData[0]); 
                    formData.append("FileId", vm.FileId);
                    formData.append("FileName", vm.getFileName);
                    formData.append("FileTitle", vm.FormSchema[0].Data[0].value);
                    formData.append("FileContent", vm.FormSchema[1].Data[0].value);
                    formData.append("UserList", vm.Userids);
                    formData.append("ProjectId", vm.ProjectDetails);
                    formData.append("TaskId", vm.taskId);
                    formData.append("RequestType", "Post");
                    formData.append("requestTypeValue", "first");
                    formData.append("ModuleName", "Project");
                await DataService.Create(formData).then(res => {
                    if (res.data.result.msg == "FileAddedMsg") {
                        this.$emit('close')
                        this.$emit('closeUpdateModal')
                        this.$emit('fetchData')
                        this.ShowAlert(this.$t('FileAddedMsg'), "success", true, this.$t('Alert'));
                    }
                    if (res.data.result.msg == "ProcessingErroeOccured") {
                        this.$emit('close')
                        this.$emit('closeUpdateModal')
                        this.$emit('fetchData')
                        this.ShowAlert(this.$t('ProcessingErroeOccured'), "danger", true, this.$t('Alert'));
                    }
                    if (res.data.result.msg == "ErrorAddFile") {
                        this.$emit('close')
                        this.$emit('closeUpdateModal')
                        this.$emit('fetchData')
                        this.ShowAlert(this.$t('ErrorAddFile'), "danger", true, this.$t('Alert'));
                    }
                }).catch(err => {
                    console.log(err);
                })
                vm.isLoading = false;
            }
        },
        updateCheckall(e, userlist) {
            //debugger;
            var vm = this;
            if (userlist.userses.length == vm.checkBoxUser.length) {
                vm.checkBoxUserType = true;
                vm.selectedUserTypeId = userlist.userTypeId;
            }
            else {
                vm.checkBoxUserType = false;
                vm.selectedUserTypeId = userlist.userTypeId;
                //vm.checkBoxAll = [];
            }

        },
        CheckUserTypeAll(e, userlist) {
            // console.log("selectedUserType",userlist.userTypeId)
            //debugger;
            var vm = this;
            if (e.target.checked) {
                userlist.userses.forEach((select) => {
                    this.checkBoxUser.push(select.id)
                })
            }
            else {
                vm.checkBoxUser = [];
            }

        },

    }
}
</script>
<style>
#AttachmentFile {
    position: relative;
}

#AttachmentFile .input-group .question-circle {
    position: absolute;
    top: -24px;
    left: 34px;
}

.custom-file .bootstrap-filestyle input {
    padding-bottom: 7px;
    margin-bottom: 3.55px;
}

.custom-file .bootstrap-filestyle .choose-file {
    margin-bottom: 4px;
}
</style>