    <script>
    import {
        defineComponent,
    } from '@vue/composition-api'
    import {
        extend,
        ValidationObserver
    } from 'vee-validate';
    import {
        userTimerInfo
    } from "../../stores/TimeTrack.js"
    import Alert from '../../Common/Alert.vue';
    import VueTimepicker from 'vue2-timepicker'
    import DatePicker from 'v-calendar/src/components/DatePicker.vue'
    import { ValidationProvider } from 'vee-validate';
    import {
        getSecondsFromDate,
        formatter,
        dateAndTimeZone
    } from "@/assets/common/vue-common.js"
    import moment from "moment"
    extend('required', {
        validate(value) {
            return {
                required: true,
                valid: ['', null, undefined].indexOf(value) === -1
            };
    
        },
        message: 'The {_field_} is required'
    
        
    });
    export default defineComponent({
        name: "Add Manual Break",
        components: {
            ValidationObserver,
            Alert,
            VueTimepicker,
            DatePicker,
            ValidationProvider
        },
        props: {
            manualData: {
                type: Object
            }
        },
        data() {
            return {
                startTime: '00:00',
                endTime: '00:00',
                date: dateAndTimeZone(moment())
            }
    
        },
        created: function () {
            this.manualData.trackDescription = ''
            this.manualData.totalHours = ''
            console.log("manuall", this.manualData);
        },
        methods: {
    
            async submit() {
                console.log("test", this.manualData)
                if (this.validHours()) {
                    this.store.$state.getMessageAlert = ""
                    await this.store.addManualyTimer(this.manualData,this);
                    if (this.store.$state.getMessageAlert.status == 0) {
                        this.$emit('close')
                        this.$emit('closeUpdateModal')
                        const url = `dateType=${this.store.$state.dateFilterType}&search=&toDate=&fromDate=&newTrackId=0`
                        this.store.getTimerListing1(url)
                        const url1 = `dateType=${this.store.$state.dateFilterType}&type=${'list'}&toDate=&fromDate=`
                        this.store.getTrackedtimings(url1)
                    }
                    this.$emit('close')
                    this.$emit('closeUpdateModal')
                }
            },
            validHours() {
                let status = false
                if (!this.startTime) {
                    this.status = false
                    this.store.alertBOxForMessage({
                        "type": 'warning',
                        "open": true,
                        "message": this.$t('PleaseEnterStartDate')
                    })
                } else if (!this.endTime) {
                    this.status = false
                    this.store.alertBOxForMessage({
                        "type": 'warning',
                        "open": true,
                        "message": this.$t('PleaseEnterEndDate')
                    })
                }
                //console.log("end",moment(moment(this.endTime.HH+':'+this.endTime.mm, 'hh:mm')))
                else if (this.startTime && this.endTime) {
    
                    let dateStart = moment(new Date(this.date), "YYYY-MM-DD").format("YYYY-MM-DD")
                    let startDateTime = moment(dateStart + ' ' + this.startTime, "YYYY-MM-DD HH:mm")
                    let endDateTime = moment(dateStart + ' ' + this.endTime, "YYYY-MM-DD HH:mm")
                    let today = moment(dateAndTimeZone(moment(),'YYYY-MM-DD HH:mm'))
                    console.log("today",today)
                    // if (startDateTime.valueOf() > endDateTime.valueOf()) {
                    //     this.store.alertBOxForMessage({
                    //         "type": 'warning',
                    //         "open": true,
                    //         "message": this.$t('FutureTime')
                    //     })
                    // } else {
                        status = true
                        let sec = getSecondsFromDate({
                            startDate: moment(this.startTime, 'hh:mm'),
                            endDate: moment(this.endTime, 'hh:mm')
                        }, 'seconds')
    
                        this.manualData.startDate = startDateTime.format("YYYY-MM-DD HH:mm:ss")
                        this.manualData.date = startDateTime.format("YYYY-MM-DD HH:mm:ss")
                        //this.manualData.SelectedDate = startDateTime.format("YYYY-MM-DD HH:mm:ss")
                        this.manualData.startTime = startDateTime.format("YYYY-MM-DD HH:mm:ss")
                        this.manualData.stopTime = endDateTime.format("YYYY-MM-DD HH:mm:ss")
                        //this.manualData.endDate = endDateTime.format("YYYY-MM-DD HH:mm:ss")
                        this.manualData.totalHours = formatter(sec)
                    //}
                }
                return status
            },
            //Get time time diffrece between start date and end date
            getTimeDiff() {
                if (this.startTime && this.endTime) {
                    let dateStart = moment(new Date(this.date), "YYYY-MM-DD").format("YYYY-MM-DD")
                    let startDateTime = moment(dateStart + ' ' + this.startTime, "YYYY-MM-DD HH:mm")
                    let endDateTime = moment(dateStart + ' ' + this.endTime, "YYYY-MM-DD HH:mm")
                    const todayDate = new Date(this.date)
                    if (startDateTime.valueOf() > endDateTime.valueOf()) {
                        todayDate.setDate(todayDate.getDate() + 1)
                        endDateTime = moment(moment(new Date(todayDate), 'DD/MM/YYYY').format('YYYY-MM-DD') + ' ' + this.endTime, "YYYY-MM-DD HH:mm")
                    }
                    // let today = moment(dateAndTimeZone(moment(),"YYYY-MM-DD HH:mm"))
                    // if (startDateTime.valueOf() > endDateTime.valueOf() || endDateTime.valueOf() > today.valueOf()) {
                    //     let today = moment(dateAndTimeZone(moment(),"YYYY-MM-DD HH:mm"))
                    //     today.setDate(today.getDate() + 1)
                    //     this.manualData.totalHours = "00:00:00"
    
                    //  } 
                     //else {
                    //     let sec = getSecondsFromDate({
                    //         startDate: moment(this.startTime, 'hh:mm'),
                    //         endDate: moment(this.endTime, 'hh:mm')
                    //     }, 'seconds')
                    //     this.manualData.totalHours = formatter(sec)
                    // }
                    if (startDateTime.valueOf() < endDateTime.valueOf()) {
                    let sec = getSecondsFromDate({
                        startDate: startDateTime,
                        endDate: endDateTime
                    }, 'seconds')
                    this.manualData.totalHours = formatter(sec)
                } else {
                    this.manualData.totalHours = "00:00:00"
                }
                }
            }
    
        },
        setup() {
            const store = userTimerInfo();
            return {
                store,
    
            }
        },
    });
    </script>
    