            async timerStopOrPause(status, type) {
                this.store.getTimer.CreatedBy = this.store.getUserInformation.id
                this.store.getTimer.createdBy = this.store.getUserInformation.id
                this.store.getTimer.currentDate = moment().format('YYYY-MM-DD HH:mm:ss')
                this.store.getTimer.timerStatus = status
                this.store.getTimer.trackType = type
                this.store.getTimer.type = type
                this.store.trackAgent = "web"
                if (status == 'pause' && type == 'TimeTrack') {
                    let countResumeInSeconds = 0
                    this.store.$state.timerCountInSec = moment(new Date(this.store.getTimer?.dateStop), "DD/MM/YYYY HH:mm:ss").format("DD-MM-YYYY") == "01-01-1950" ?
                        getSecondsFromDate({
                            startDate: this.store.getTimer?.dateStart,
                            endDate: moment()
                        }, 'seconds') : countResumeInSeconds + parseInt(this.store.getTimer.resumeHours)
                    this.store.getTimer.stopTime = moment().format('YYYY-MM-DD HH:mm:ss')
                    this.store.getTimer.totalHours = this.store.$state.timerCountInSec
                    await this.store.submitProjectInfo(this.store.getTimer,this)
                    await this.store.getTimerInfo();
                    this.urlChange()
                    this.store.stopTimer()
                } 
                else if (status == 'stop' && type == 'TimeTrack') {
                    this.store.getTimer.stopTime = moment().format('YYYY-MM-DD HH:mm:ss')
                    this.store.getTimer.startTime = moment().format('YYYY-MM-DD HH:mm:ss')
                    this.store.getTimer.totalHours = this.store.$state.timerCountInSec
                    await this.store.submitProjectInfo(this.store.getTimer,this)
                    await this.store.getTimerInfo();
                    this.urlChange()
                    this.store.stopTimer()
                    this.store.$state.timerCountInSec = 0
                    this.store.$state.timerClock = "00:00:00"
                } 
                else if (status == 'resume' && type == 'TimeTrack') {
                    this.store.getTimer.startTime = moment().format('YYYY-MM-DD HH:mm:ss')
                    this.store.getTimer.stopTime=moment().format('YYYY-MM-DD HH:mm:ss')
                    await this.store.submitProjectInfo(this.store.getTimer,this)
                    await this.store.getTimerInfo();
                    this.urlChange()
                    this.store.$state.timerCountInSec = parseInt(this.store.getTimer.resumeHours)
                    this.store.startTimer()
                }    
                this.FetchData();               
            },
