            ResetPastActivitydata: function () {
                this.taskName = '';
                this.IsTaskNameSearch = false;
                this.projectName = '';
                this.IsProjectNameSearch = false;
                this.Status = '';
                this.IsStatusSearch = false;
                this.StartDateForSearch = '';
                this.IsStartDateSearch = false;
                this.AssignedBy = '';
                this.IsAssignedBySearch = false;
                this.ModuleNameForSearch = '';
                this.ModuleNameAll = '';
                this.IsModuleNameSearch = false;
                this.IsAnySearch = false;
                this.FetchDataPostActivity('');
            },
            async FetchDataPostActivity(dataType) {
                var vm = this;
                if (dataType != undefined && dataType != "") {
                    vm.ActivityDataType = dataType;
                } else {
                    dataType = vm.ActivityDataType;
                }
                //showLoader();
                vm.isLoading = true;
    
                var url = "dataType=" + dataType + "&pageSize=" + vm.PageSize + "&pageNumber=" + vm.PageNumber + "&sortBy=" + vm.SortBy + "&sortExp=" + vm.SortExp;
                //if (!this.isBlank(vm.taskName) && vm.CheckType== false) {
                if (!vm.isBlank(vm.taskName)) {
                    url = url + "&taskName=" + vm.taskName;
                    vm.IsTaskNameSearch = true;
                    vm.IsAnySearch = true;
                }
                //else if (!this.isBlank(vm.projectName) && vm.CheckType== false) {
                if (!vm.isBlank(vm.projectName)) {
                    url = url + "&projectName=" + vm.projectName;
                    vm.IsProjectNameSearch = true;
                    vm.IsAnySearch = true;
                }
                // url = baseUrl + "api/Project/GetPastActivityDetails" + url;
                // vm.$http.get(url, {
                //     headers: { 'Authorization': 'bearer @tokenid' }
                // })
    
                await DataService.GetPastActivityDetails(url).then(function (response) {
                    //debugger
                    vm.isLoading = false;
                    //hideLoader();
                    if (response.data != null && response.data != "") {
                        vm.PastActivityData = response.data.result.data;
                        if (vm.ActivityDataType != '') {
                            $("#ddlSearch").val(vm.ActivityDataType);
                        } else {
                            $("#ddlSearch").val('today');
                        }
                        vm.PastActivityData.forEach((item, index) => {
                            
                            if (item.TRACK_AGENT != 'timesheet') {
                                vm.pastActivitywithoutDisabled.push(item);
                            }
                        })
                        vm.FetchData();
                        if (vm.PastActivityData.length > 0) {
                            //debugger;
                            if (vm.IsAnySearch != true) {
                                vm.TotalRecordsPastActivity = response.data.result.TOTAL_COUNT;
                            } else {
                                vm.TotalRecordsPastActivity = response.data.result.data.length;
                            }
                            vm.TotalPages = Math.ceil(vm.TotalRecordsPastActivity / vm.PageSize);
                            vm.CurrentPage = vm.PageNumber;
                            $("[id^='chkAll']").prop("checked", false).removeAttr('checked');
                            $('.chkItems:checkbox:checked').prop("checked", false).removeAttr('checked');
                            vm.noRecord = false;
                        } else {
                            vm.TotalRecordsPastActivity = 0;
                            vm.TotalPages = Math.ceil(vm.TotalRecordsPastActivity / vm.PageSize);
                            vm.CurrentPage = vm.PageNumber;
                            vm.noRecord = true;
                        }
    
                    } else {
                        vm.noRecord = true;
                    }
                });
            },
            SetClass: function (item) {
                var className = "";
                if (item.TRACK_AGENT == 'timesheet') {
                    className = 'lgtr-timesheet';
                } else if (item.STATUS_CODE == 'ACT' && item.TRACK_AGENT == 'Web') {
                    className = 'lgtr-timesheet';
                } else if (item.TRACK_AGENT == 'Web_Manual') {
                    className = 'lgtr-addedmanually';
                } else if (item.STATUS_CODE == 'TRACK_ENTRY_ADD_MANUAL_PENDING' && item.TRACK_AGENT == 'Web') {
                    className = 'lgtr-pendingred';
                } else if (item.TRACK_AGENT == 'bulk') {
                    className = 'medium-bar';
                } else if (item.TRACK_AGENT == 'Third_Party') {
                    className = 'lgtr-pausedresumed';
                } else if (item.TRACK_AGENT == 'pending') {
                    className = 'lgtr-legends_profile';
                } else if (item.TRACK_AGENT == 'approved') {
                    className = 'lg-approved';
                } else if (item.TRACK_AGENT == 'TRACK_ENTRY_APPROVED') {
                    className = 'lgtr-approved';
                } else if (item.PAUSED_HOURS > 0) {
                    className = 'critical-bar';
                }
                return className;
            },
            ConvertToTimeFormatHHMMSS: function (seconds) {
                if (seconds != "") {
                    var value = moment().startOf('day').seconds(seconds).format('HH:mm:ss');
                    return value;
                }
    
            },
            async commonBillableData(event, type) {
                var vm = this;
                var val = "";
                $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                    if (val.length > 0)
                        val += ',';
                    val += $(this).val();
                });
                if (val.length > 0) {                  
                    var url = "id=" + val + "&type=" + type;
                    DataService.UpdateBillableEntry(url).then(function (response) {
                        vm.isLoading = false;
                        if (response.data.result.toString() == "1") {                           
                            vm.ShowAlert(vm.$t('UpdatedSuccess',[vm.$t('Record')]),"success", true, vm.$t("Alert"));
                            vm.FetchDataPostActivity();
                        } else {
                            vm.ShowAlert(vm.$t('ProcessingError'), "failure", true, vm.$t('Alert'));
                        }
                        vm.isLoading = false;
                    }, function (response) {
                        vm.isLoading = false;
                    });
                } else {
                    vm.ShowAlert(vm.$t('SelectForAttend'),"warning", true, vm.$t('Alert'));
                }
            },
            StatusDropdown: function () {
                var vm = this;
                //showLoader();
    
                var url = "langCode=en&statusType=Project&hasGlobal=1";
                DataService.StatusDropdown(url).then(function (response) {
                    //hideLoader();
                    if (response.data != null && response.data != "") {
                        //vm.StatusData = response.data.result.data;
                        vm.StatusList = response.data.result.data;
    
                        vm.pendingData = $.grep(vm.StatusList, function (element, index) {
                            return element.STATUS_CODE == 'REFPEN';
                        });
                        vm.inprogressData = $.grep(vm.StatusList, function (element, index) {
                            return element.STATUS_CODE == 'PNPGRS';
                        });
                        vm.comData = $.grep(vm.StatusList, function (element, index) {
                            return element.STATUS_CODE == 'STATUS_DONE';
                        });
                    }
                });
            },
            ChangeStatusDrag: function (evt, status) {
                var vm = this;
                debugger;
                var isChange = false;
                vm.isLoading = true;
    
                // console.log('Status',status);
                //console.log('Event',evt.added.element.STATUS_ID);
                //console.log('comData STATUS_ID',vm.comData[0].STATUS_ID);
                //console.log('inprogressData STATUS_ID',vm.inprogressData[0].STATUS_ID);
    
                if (status != 2222) {
                    if (typeof evt.added != 'undefined') {
                        if (evt.added.element.STATUS_ID == 1005 && status == vm.comData[0].STATUS_ID) {
                            isChange = true;
                        }
                        if (evt.added.element.STATUS_ID == 1005 && status == vm.inprogressData[0].STATUS_ID) {
                            isChange = true;
                        }
                        if (evt.added.element.STATUS_ID == vm.pendingData[0].STATUS_ID && status == vm.comData[0].STATUS_ID) {
                            isChange = true;
                        }
                        if (evt.added.element.STATUS_ID == vm.pendingData[0].STATUS_ID && status == vm.inprogressData[0].STATUS_ID) {
                            isChange = true;
                        }
                        if (evt.added.element.STATUS_ID == vm.inprogressData[0].STATUS_ID && status == vm.comData[0].STATUS_ID) {
                            isChange = true;
                        }
                        if (isChange) {
                            var VarObject = {
                                ID: evt.added.element.TASK_ID,
                                StatusId: status,
                                IsFor: 'TODOKANBANLISTING'
                            }
                            var objectPostString = JSON.stringify(VarObject);
                            // vm.$http.post(baseUrl + 'api/Common/CommonUpdateStatus', { postString: objectPostString },
                            DataService.UpdateStatus(objectPostString).then(function (response) {
                                // debugger;
                                //showLoader();
                                vm.isLoading = true;
    
                                if (response.data != null) {
                                    if (response.data.status === 'Success') {
                                        vm.cardViewData = [];
                                        vm.PageNumber = 1;
                                        $("#hdfStartIndex").val(1);
                                        $("#hdfEndIndex").val(10);
                                        vm.FetchData('kanban', '');
                                        vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success", true, vm.$t('Alert'));
                                    } else {
                                        vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                                    }
                                } else {
                                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                                }
                                //hideLoader();
                                vm.isLoading = false;
                            });
                        } else {
                            vm.cardViewData = [];
                            vm.PageNumber = 1;
                            $("#hdfStartIndex").val(1);
                            $("#hdfEndIndex").val(10);
                            vm.FetchData('kanban', '');
                            vm.ShowAlert("Dragging between these two status is not allowed.", "warning", true, vm.$t('Alert'));
                            vm.isLoading = false;
                        }
                    }
                } else {
                    vm.cardViewData = [];
                    vm.PageNumber = 1;
                    $("#hdfStartIndex").val(1);
                    $("#hdfEndIndex").val(10);
                    vm.FetchData('kanban', '');
                    vm.ShowAlert("Dragging not allowed in upcoming status.", "warning", true, vm.$t('Alert'));
                }
                vm.isLoading = false;
                // hideLoader();
            },
    
            async commonDeleteData(event) {
                if ($(event.target).hasClass("disabled") || $(event.target).closest("a.iconenable").hasClass("disabled")) {
                    return false;
                }
                var vm = this;
                var val = "";
                $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                    if (val.length > 0)
                        val += ',';
                    val += $(this).val();
                });
                if (val.length > 0) {     
                    vm.confirmR(vm.$t("Delete_Confirmation"), true, (vm.$t("Delete")), function () {
                        var url = "id=" + val;
                        DataService.DeleteTimeEntry(url).then(function (response) {
                            vm.isLoading = false;
                            if (response.data.result.toString() == "1") {   
                                vm.ShowAlert(vm.$t('DeletedSuccess',[vm.$t('RecordsDeleteSuccessfully')]),"success", true, vm.$t("Alert"));
                                vm.FetchDataPostActivity();
                            } else {
                                vm.ShowAlert(vm.$t('ProcessingError'), "", "failure", true, vm.$t('Alert'));
                            }
                            vm.isLoading = false;
                        }, function (response) {
                            vm.isLoading = false;
                        });
                    });
                } 
                else {
                    vm.ShowAlert(vm.$t('Selectanyrecordtodelete'), "warning", true, vm.$t('Alert'));
                }
            },
            changePostActivity: function (event) {
                var vueObj = this;
                var dataType = event.target.value;
                $.cookie("pastactview", dataType);
                vueObj.PageNumber = 1;
                vueObj.FetchDataPostActivity(dataType);
            },
            checkAll(e) {
                //debugger
                var vm = this;
                if (e.target.checked) {
                    vm.pastActivitywithoutDisabled.forEach((item, index) => {
                        vm.checkClass = true;
                        vm.SeletedCheckArray.push(item.TRACK_ID);
                    })
                } else {
                    vm.checkClass = false;
                    vm.SeletedCheckArray = [];
                }
            },
            updateCheckall: function (e) {
                var vm = this;
                vm.SeletedCheckArray = [];
                $('.chkItems:checkbox:checked').each(function () {
                    vm.SeletedCheckArray.push($(this).val());
                })
                if (vm.SeletedCheckArray.length == vm.pastActivitywithoutDisabled.length) {
                    vm.isCheckAll = true;
                } else {
                    vm.isCheckAll = false;
                }
            },
            openNoteListPopUp: function (item, index) {
                 debugger
