<template lang="en">
<transition name="modal">
    <div class="my-popups">
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">
                            {{$t('Notes')}}
                        </h5>
                        <span class="float-right"><a href="javascript:;" class="text-white" title="" data-toggle-tooltip="tooltip" data-original-title="Card View" v-on:click="NoteListType = 'card'" v-if="NoteListType == 'list'"><i class="fa fa-th-large"></i> {{$t('CardView')}} </a>
                            <a href="javascript:;" class="text-white" title="" data-toggle-tooltip="tooltip" data-original-title="List View" v-on:click="NoteListType = 'list'" v-if="NoteListType != 'list'"><i class="fa fa-list"></i> {{$t('ListView')}} </a></span>
                        <button v-on:click="$emit('close')" href="javascript:;" class="close"><i class="fa fa-times" aria-hidden="true"></i></button>
                    </div>
                    <div class="modal-body" style="max-height:600px;overflow-y:auto;">
                        <div class="col-12 p-0">
                            <div class="container-fluid p-0">
                                <div style="clear:both;"></div>
                                <div class="pb-2 d-inline-block">
                                    <span class="legend-Progress colorboxsquare"></span>{{$t('PrivateNOTE')}}
                                    <span class="legend-upcoming colorboxsquare ml-3"></span>{{$t('PublicNOTE')}}
                                </div>
                                <div v-if="NoRecordForTab" class="text-center text-danger p-2 border">{{$t('NoRecordfound')}}</div>
                                <div style="clear:both;"></div>

                                <div v-if="NoteListType != 'list'" class="row ticket-card-container card-view bg-border p-0">
                                    <div style="min-width:257px" class="col-md-12 col-lg-6 col-xl-3 mb-3" v-for="item in NoteData" v-if="!NoRecordForTab">

                                        <div v-bind:class="{'card-box':true, 'blue-bg-light': item.IS_PUBLIC, 'green-bg-light': !item.IS_PUBLIC} ">
                                            <div class="card-heading d-flex align-items-center">                                            
                                                  <span class="initials user-img-con mr-2">
                                                      {{ getFirstTwoInitials(item.POSTED_BY) }}
                                                  </span>
                                                
                                                {{item.POSTED_BY}}
                                            </div>
                                            <div class="card-detail-main" style="max-height: 150px;">
                                                <div class="card-detail" v-if="item.IS_PUBLIC==true"><i class="fa fa-users" aria-hidden="true"></i><span>
                                                        <p>{{$t('Public')}}</p>
                                                    </span></div>
                                                <div class="card-detail" v-if="item.IS_PUBLIC!=true"><i class="fa fa-users" aria-hidden="true"></i><span>
                                                        <p>{{$t('Private')}}</p>
                                                    </span></div>
                                                <div class="card-detail"><span>
                                                        <p v-html="item.NOTE_CONTENT"></p>
                                                    </span></div>

                                                <div class="bottom-action">
                                                    <div class="card-date"><i class="fa fa-calendar-o" aria-hidden="true"></i> <span>{{item.CREATED_AT | formatDateTime}}</span></div>

                                                    <div class="card-action">
                                                        <a href="javascript:;" v-if="(userid == item.CREATED_BY)" title="Edit" v-bind:class="{'disabled': disabledAddNote}" class="round-icon-small btn-success-light" v-on:click="OpenEditNote(item)">
                                                            <i class="fa fa-pencil" aria-hidden="false"></i>
                                                        </a>                                                     
                                                        <a href="javascript:;" class="round-icon-small btn-danger-light" title="Delete" v-on:click="DeleteNote(item)">
                                                            <i class="fa fa-trash" aria-hidden="true"></i>
                                                        </a>
                                                    </div>
                                                </div>

                                            </div>

                                        </div>
                                    </div>
                                </div>
                                <div class="conversation-main" v-if="NoteListType == 'list'">
                                    <template v-for="item in NoteData" v-if="!NoRecordForTab">                                      
                                        <div class="conversation-time"><span>{{timeFormatOnly(item.CREATED_AT)}}</span></div>
                                        <div class="conversation-box-con">
                                            <div v-bind:class="{'conversation-box':true, 'public-note': item.IS_PUBLIC, 'private-note': !item.IS_PUBLIC} ">
                                                
                                               <div class="name-circle light-grey" v-if="item.USER_IMAGE_PATH != null && item.USER_IMAGE_PATH != ''">
                                                    <img class="img-circle avatar img-max-width" v-bind:src="item.USER_IMAGE_PATH" alt="" />
                                                </div> 

                                                <div class="initials name-circle light-grey" v-else>
                                                     {{ getFirstTwoInitials(item.POSTED_BY) }}
                                                </div>                       
                                               
                                                <div class="conversation-header">
                                                    <span>
                                                        <span class="sender-name">{{item.POSTED_BY}}</span>
                                                        <span class="sender-department">(<small class="text-danger font-14" v-bind:title="item.CREATED_AT | formatDateTime">{{item.CREATED_AT | formatDateTime}}</small>)</span>
                                                    </span>                                                    
                                                    <span class=""><a v-if="(userid == item.CREATED_BY )" title="Delete" href="javascript:;" class="round-icon-small btn-danger-light float-right" v-on:click="DeleteNote(item)">
                                                            <i class="fa fa-trash" aria-hidden="true"></i>
                                                        </a>
                                                        <a href="javascript:;" v-if="(userid == item.CREATED_BY)" v-bind:class="{'disabled': disabledAddNote}" title="Edit" class="round-icon-small btn-success-light float-right" v-on:click="OpenEditNote(item)">
                                                            <i class="fa fa-pencil" aria-hidden="true"></i>
                                                        </a></span>

                                                </div>
                                                <div class="conversation-content">
                                                    <p v-html="item.NOTE_CONTENT"></p>
                                                </div>
                                            </div>
                                        </div>
                                    </template>
                                </div>

                                <div class="border-top-paging thispagebod-full" v-show="!NoRecordForTab && NoteData.length > 0">
                                    <pager-control v-bind:numberofrecords="TotalRecords" v-bind:callbackfunction="FetchNotes" prev-text="Prev" first-text="First" last-text="Last" next-text="Next"></pager-control>
                                </div>

                                <div class="modal-footer pr-0">
                                    <div class="col-lg-6 text-right p-0 mr-0">
                                        <a href="javascript:;" v-bind:class="{'disabled': disabledAddNote}" class="btn btn-success formbtn text-white" v-on:click="OpenNote()"><i class="fa fa-plus pr-2"></i>{{$t('AddNoteTab')}}</a>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</transition>
</template>

<script>
import DataService from '../../services/DataService';
import moment from 'moment';

export default {
    props: {
        notedata: {
            type: Array,
            required: false
        },

        userid: {
            type: Number,
            required: true
        },
        companyid: {
            type: Number,
            required: false
        },
        projectid: {
            type: Number,
            required: true
        },
        taskId: {
            type: Number,
            required: true
        },
        ispublic: {
            type: Boolean,
            required: false
        },
        pageSize: {
            type: Number,
            required: false
        },
        pageNum: {
            type: Number,
            required: false
        },
        sortBy: {
            type: String,
            required: false
        },
        sortExp: {
            type: String,
            required: false
        },
        numberofrecords: {
            type: Number,
            required: false
        },
        tokenid: {
            type: String,
            required: false
        },
        reqfrom: {
            type: String
        }

    },
    data: function () {
        return {
            NoteData: [],
            NoRecordForTab: true,
            note: '',
            TotalRecords: 0,
            TotalPages: 0,
            PageSize: 10,
            PageSizeOption: null,
            CurrentPage: 1,
            GroupStart: 1,
            GroupEnd: 3,
            ModelSortBy: '',
            ModelSortExp: '',
            modalDeleteItem: null,
            NoteListType: "card",
            TaskId: null,
            typeNoteTask: '',
            ticketStatus: '',
            disabledAddNote: false,

        }
    },
    watch: {
        notedata: function (value) {
            //debugger;
            this.NoteData = value;
            this.TotalRecords = this.numberofrecords;
            this.ProjectId = this.projectid;
            this.TokenId = this.tokenid;
            this.ModelSortBy = (this.sortBy == undefined) ? '' : this.sortBy;
            this.ModelSortExp = (this.SortExp == undefined) ? '' : this.SortExp;
            this.NoRecordForTab = (this.NoteData != null && this.NoteData.length > 0) ? false : true;
        }
    },
    created: function () {     
        if (this.reqfrom == "dashboard") {
            this.ProjectId = this.$parent.modalNoteTaskItem.PROJECT_ID;
            this.TaskId = this.$parent.modalNoteTaskItem.TASK_ID;
            this.ticketStatus = this.$parent.modalNoteTaskItem.STATUS_NAME;
        } else {
            this.ProjectId = this.$parent.modalNoteTaskItem.ProjectId;
            this.TaskId = this.$parent.modalNoteTaskItem.TaskId;

        }
        if (this.ticketStatus == 'Closed' || this.ticketStatus == 'Closed and Locked') {
            this.disabledAddNote = true;
        } else {
            this.disabledAddNote = false;
        }
        this.typeNoteTask = this.$parent.typeNoteTask;
        this.FetchNotes();        
    },
    methods: {
        DeleteNote: function (item) {
            // debugger;
            //if (GetPrivilege("/Project/DeleteNote", true, false)) {
            this.modalDeleteItem = item;
            this.DeleteNoteData(this.modalDeleteItem.NOTE_ID);
            //}
        },
        DeleteNoteData: function (id) {
            var vm = this;
            if (id > 0) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("ConfirmDelete")), function () {
                    var postJSON = {
                        ids: id,
                        companyId: vm.$parent.CompanyId,
                        userId: vm.$parent.UserId,
                        moduleName: vm.$parent.ModuleName,
                        subModuleCode: "Project_Detail",
                        refCode: 'TALYGEN_NOTES',
                        refId: vm.$parent.ProjectId
                    };
                    var objectPostString = JSON.stringify(postJSON);
                    DataService.CommonCommonDelete(objectPostString).then(function (response) {
                        if (response.data[0].Status == "Success") {

                            vm.ShowAlert(vm.$t('DeletedSuccessfully'), "Success", true, vm.$t('Alert'));
                            vm.FetchNotes();
                            vm.$parent.FetchData('kanban', null);
                        } else {
                            vm.ShowAlert(vm.$t('DeleteError'), "warning", true, vm.$t('Alert'));
                        }
                        vm.isLoading = false;
                    }, function (response) {
                        vm.isLoading = false;
                    });

                });
            }
        },
        FetchNotes: function () {
            debugger
            var vm = this;
            vm.noteData = [];
            vm.PageNumber = (vm.PageNumber == undefined) ? 1 : vm.PageNumber;
            if(vm.taskId>0){
                vm.TaskId=vm.taskId;
            }
            var params = "projectId=" + vm.ProjectId + "&isPublic=" + true + "&taskId=" + vm.TaskId + "&sortBy=" + vm.ModelSortBy + "&sortExp=" + vm.ModelSortExp + "&pageSize=" + vm.PageSize + "&pageNum=" + vm.PageNumber;
            DataService.ProjectNoteListingByTask(params).then(function (response) {
                //debugger
                vm.isLoading = false;
                if (response.data.result.data[0] != null && response.data.status == "Success") {
                    //debugger
                    vm.NoteData = response.data.result.data;
                    vm.TotalRecords = response.data.result.data[0].TOTALRECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = (vm.PageNumber == undefined) ? 1 : vm.PageNumber;
                    // setTimeout("CheckBoxBootstrap()", 100);
                    vm.NoRecordForTab = false;
                } else {
                    vm.NoRecordForTab = true;
                }
            });
        },
        OpenNote: function () {
            //debugger;
            //if (GetPrivilege('/Project/AddNoteInProject', true, false)) {
            this.$emit("close");
            this.$parent.openProjectNoteModel(null, this.TaskId, this.typeNoteTask)
            //}
        },
        OpenEditNote: function (item) {
            //debugger;
            //if (GetPrivilege('/Project/EditNote', true, false)) {
            this.$emit("close");
            this.$parent.openProjectNoteModel(item, this.TaskId, this.typeNoteTask)
            //}
        },
        timeFormatOnly: function (value) {
            //debugger;
            if (value) {
                //return moment(value).format('hh:mm a');
                return moment(value).format('hh:mm a').toUpperCase();
            }
        },
        getFirstTwoInitials(fullName) {
            debugger
            if (!fullName) return "";

            const parts = fullName.trim().split(/\s+/);
            return (parts[0][0] + (parts[1]?.[0] || "")).toUpperCase();
        }
    }

}
</script>
<style>
/* .initials.user-img-con{ line-height: 34px;text-align: center; font-size: 12px; font-weight: 400; background: rgba(195, 207, 213, 0.84);} */
.conversation-box .initials.name-circle{ line-height: 55px;text-align: center; font-size: 20px;  background: rgba(195, 207, 213, 0.84);}
</style>