                //     if(this.store.timerInfo.statusCode=="PAUS" && this.store.timerInfo.trackType=='TimeTrack'){
                //       this.timerUpdateInfo('resume','TimeTrack')
                //     }
                // }
            },
            toggleWeeklyStatus() {
                //debugger
                if (!this.isActiveWeeklyStatus) {
                    this.isActiveWeeklyStatus = true;
                } else {
                    this.isActiveWeeklyStatus = false;
                }
            },
    
            showTrackPercent: function (item) {
                //debugger;
                var percent = 0;
                percent = (item.TRACKED_HOURS / ((item.ALLOCATE_HOURS) * 3600));
                percent = percent * 100;
                percent = parseFloat(percent, 10).toFixed(1);
                //if(percent==0)
                //{
                //    percent= item.ALLOCATE_HOURS * 3600;
                //}
                if (percent <= 0 || isNaN(percent) || percent.toLowerCase() == 'infinity') {
                    percent = 100;
                } else {
                    percent = 100 - percent;
                }
                if (Math.sign(percent) < 0) {
                    percent = 0;
                }
                percent = Math.round(parseFloat(percent, 10));
                return percent;
            },
            formatOnlyMonthYearWithComma: function (value) {
                //debugger;
                if (value) {
                    return moment(value).format('MMM') + ', ' + moment(value).format('YYYY');
                }
            },
            formatOnlyDate: function (value) {
                if (value) {
                    return moment(value).format('DD');
                }
            },
            convertSecondsToHHMMSS: function (intSecondsToConvert) {
    
                var hours = this.convertHours(intSecondsToConvert);
                var minutes = this.getRemainingMinutes(intSecondsToConvert);
                minutes = minutes == 60 ? "00" : minutes;
                // var seconds = this.getRemainingSeconds(intSecondsToConvert);
                if (hours < 10) hours = "0" + hours;
                if (minutes < 10) minutes = "0" + minutes;
                //if (seconds < 10) seconds = "0" + seconds;
                return hours + ":" + minutes;
            },
            calculateWeekHoursAVG: function (totalHours, days) {
                var avgPerWeekHours = Math.floor(totalHours / days);
                if (isNaN(avgPerWeekHours)) {
                    avgPerWeekHours = 0;
                }
                return avgPerWeekHours
            },
            convertSecondsToHHMMSSNew: function (intSecondsToConvert) {
                var hours = this.convertHours(intSecondsToConvert);
                var minutes = this.getRemainingMinutes(intSecondsToConvert);
                minutes = minutes == 60 ? "00" : minutes;
                var seconds = this.getRemainingSeconds(intSecondsToConvert);
                if (hours < 10) hours = "0" + hours;
                if (minutes < 10) minutes = "0" + minutes;
                if (seconds < 10) seconds = "0" + seconds;
                return hours + ":" + minutes + ":" + seconds;
            },
            convertHours: function (intSeconds) {
                var minutes = this.convertMinutes(intSeconds);
                var hours = Math.floor(minutes / this.minutesPerHour);
                return hours
            },
            convertHoursTwoDecimal: function (intSeconds) {
    
                var minutes = this.convertMinutes(intSeconds);
                var hours = (minutes / this.minutesPerHour).toFixed(2);
                return hours
            },
            convertMinutes: function (intSeconds) {
                return Math.floor(intSeconds / this.secondsPerMinute)
            },
            getRemainingMinutes: function (intSeconds) {
                var intTotalMinutes = this.convertMinutes(intSeconds);
                return intTotalMinutes % this.minutesPerHour
            },
            getRemainingSeconds: function (intTotalSeconds) {
                return intTotalSeconds % this.secondsPerMinute
            },
            splitTimeZone: function (item) {
                var fullname = item.split(' ');
                var sortname = item.split(')');
                return fullname[0];
            },
            splitTags: function (item) {
                return (item != null) ? item.split(",") : [];
            },
            convertSecondsToHH: function (intSecondsToConvert) {
    
                var hours = this.convertHoursTwoDecimal(intSecondsToConvert);
                if (hours < 10) hours = "0" + hours;
                return hours + " hrs "
            },
    
