                                vueObj.OverdueRecords = response.data.result.DATA[0].OVERDUERECORDS;
                                vueObj.UpcomingRecords = response.data.result.DATA[0].UPCOMINGRECORDS;
                                vueObj.CompletedRecords = response.data.result.DATA[0].COMPLETEDRECORDS;
                                //debugger;
                                vueObj.TotalPages = Math.ceil(vueObj.TotalRecords / vueObj.PageSize);
                                vueObj.CurrentPage = vueObj.PageNumber;
                                //debugger;
                                //vueObj.MaxCount = Math.max(vueObj.PendingRecords, vueObj.ProgressRecords, vueObj.OverdueRecords, vueObj.UpcomingRecords, vueObj.CompletedRecords);
                                //setTimeout(function () {
                                // ScrollKanbanView();
                                // }, 500);
    
                                vueObj.noRecordToDoList = false;
    
                            } else {
                                vueObj.TotalRecords = 0;
                                vueObj.ProgressRecords = 0;
                                vueObj.PendingRecords = 0;
                                vueObj.OverdueRecords = 0;
                                vueObj.UpcomingRecords = 0;
                                vueObj.CompletedRecords = 0;
                                vueObj.noRecordToDoList = true;
    
                            }
                        } else {
                            vueObj.TotalRecords = 0;
                            vueObj.ProgressRecords = 0;
                            vueObj.PendingRecords = 0;
                            vueObj.OverdueRecords = 0;
                            vueObj.UpcomingRecords = 0;
                            vueObj.CompletedRecords = 0;
