                        if (isChange) {
                            var VarObject = {
                                ID: evt.added.element.TASK_ID,
                                StatusId: status,
                                IsFor: 'TODOKANBANLISTING'
                            }
                            var objectPostString = JSON.stringify(VarObject);
                            // vm.$http.post(baseUrl + 'api/Common/CommonUpdateStatus', { postString: objectPostString },
                            DataService.UpdateStatus(objectPostString).then(function (response) {
                                // debugger;
                                //showLoader();
                                vm.isLoading = true;
    
                                if (response.data != null) {
                                    if (response.data.status === 'Success') {
                                        vm.cardViewData = [];
                                        vm.PageNumber = 1;
                                        $("#hdfStartIndex").val(1);
                                        $("#hdfEndIndex").val(10);
                                        vm.FetchData('kanban', '');
                                        vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success", true, vm.$t('Alert'));
                                    } else {
                                        vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                                    }
                                } else {
                                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                                }
                                //hideLoader();
                                vm.isLoading = false;
                            });
                        } else {
                            vm.cardViewData = [];
                            vm.PageNumber = 1;
                            $("#hdfStartIndex").val(1);
                            $("#hdfEndIndex").val(10);
                            vm.FetchData('kanban', '');
                            vm.ShowAlert("Dragging between these two status is not allowed.", "warning", true, vm.$t('Alert'));
                            vm.isLoading = false;
                        }
                    }
                } else {
                    vm.cardViewData = [];
                    vm.PageNumber = 1;
                    $("#hdfStartIndex").val(1);
                    $("#hdfEndIndex").val(10);
                    vm.FetchData('kanban', '');
                    vm.ShowAlert("Dragging not allowed in upcoming status.", "warning", true, vm.$t('Alert'));
                }
                vm.isLoading = false;
                // hideLoader();
            },
